#include <iostream>
#include <algorithm>
using namespace std;
struct student
{
    int chinese,math,english,sum,num;
};
student a[305];
bool cmp(student x,student y)
{
    if(x.sum!=y.sum)
    {
        return x.sum>y.sum;
    }
    else if(x.chinese!=y.chinese)
    {
        return x.chinese>y.chinese;
    }
    else
    {
        return x.num<y.num; 
    }
}
int main()
{
    int n;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i].chinese>>a[i].math>>a[i].english;
        a[i].num=i+1;
        a[i].sum=a[i].chinese+a[i].math+a[i].english;
    }
    sort(a,a+n,cmp);
    for(int i=0;i<=4;i++)
    {
        cout<<a[i].num<<" "<<a[i].sum<<endl;
    }
    return 0;
}
